      module: 'apn.COverlayPage',
      BG: { fillStyle: '#FFFFFF' },
      SPT: {
        spt_EvtBubble:
          'if( !Event.target ) {\n    if( Event.type == "Page Create" ) {\n        onPageCreate();\n    } else if( Event.type == "Page Run" ) {\n        onPageRun();\n    } else if( Event.type == "Custom Event") {\n        if( Event.param.indexOf("onChangeNav") > -1 ) {\n            onChangeNav();\n        } else if( Event.param.indexOf("onChangeMenu") > -1 ) {\n            onChangeMenu();\n        } else if( Event.param.indexOf("onChangeMenu") > -1 ) {\n            onChangeMenu();\n        }\n    }\n} else {\n    const label = Event.target.get("label");\n    if( Event.type == "Tap Start" ) {\n        if( label == "mlc$start" ) {\n            linkTo(getPage("Page 2"), {reset : true});\n        } else if( label == "i$home") {\n            linkTo(1, {reset: true}); // Page 1\n        } else if( label == "mlc$lang") {\n            onClickLang();\n        } else if( label == "mlc$menu_fabEx" ) {\n            linkTo(1, {reset: true}); // Page 1\n        } else if( label == "mlc$menu_fabIn" ) {\n            linkTo(3, {reset: true}); // Page 2\n        } else if( label == "i$prev" ) {\n            onClickPrev();\n        } else if( label == "i$next" ) {\n            onClickNext();\n        } else if( label == "mlc$menu_floors" ) {\n            onClickFloors();\n        } else if( label == "r$floorButton_3" ) {\n            linkTo(4, {reset: true}); // Page 5\n        } else if( label == "r$floorButton_2" ) {\n            linkTo(5, {reset: true}); // Page 4\n        } else if( label == "r$floorButton_1" ) {\n            linkTo(6, {reset: true}); // Page 3\n        } else if( label == "r$overviewButton" ) {\n            linkTo(3, {reset: true}); // Page 2\n        }\n    }\n}\n\nfunction onPageCreate() {\n    File.set("lang",$W("mlc$lang").get("state") == "Layer1" ? "ko" : "en");\n    File.set("filter:pages",File.browse("pages"));\n    $W("t$totalPage").set("text",File.get("filter:pages").length);\n}\n\nfunction onPageRun() {\n    \n}\n\nfunction onChangeNav() {\n    const labelPageNum = Event.param.split("||")[1];\n    const prevButton = $W("i$prev");\n    const nextButton = $W("i$next");\n    const totalPage = File.get("filter:pages").length;\n\n    let page = File.get("filter:pages").findIndex(p => p.label == `Page ${labelPageNum}`);\n    page++;\n\n    prevButton.set("visibility",page == 1 ? "visibleEventPass" : "visible");\n    nextButton.set("visibility",page == totalPage ? "visibleEventPass" : "visible");\n    prevButton.opacityTo(page == 1 ? 0.5 : 1);\n    nextButton.opacityTo(page == totalPage ? 0.5 : 1);\n    \n    $W("t$page").set("text",page);\n    $W("mlc$menu_floors").changeState("Layer1");\n    $W("mlc$menu_floors_sub").set("visibility","hidden");\n    \n    set("$labelPageNum",labelPageNum);\n}\n\nfunction onChangeMenu() {\n    const menuConfig = JSON.parse(Event.param.split("||")[1]);\n    Object.entries(menuConfig).forEach(([key, value]) => {\n        const menu = $W(`mlc$menu_${key}`);\n        menu.set("visibility",!value.visible ? "hidden" : "visible");\n        if(value.active !== undefined) {\n            menu.set("visibility",!value.active ? "visible" : "visibleEventPass");\n            menu.changeState(`Layer${!value.active ? 1 : 2}`);\n        }\n        if(value.productName !== undefined) {\n            $W("t$product").set("text",value.productName);\n        }\n    });\n    $W("mlc$menu_floors").changeState("Layer1");\n    $W("mlc$menu_floors_sub").set("visibility","hidden");\n}\n\nfunction onClickLang() {\n    const excludeLabels = [\'Page 15\', \'Page 16\', \'Page 17\', \'Page 20\', \'Page 27\', \'Page 28\']; // EN 설정 시 제외하고 싶은 레이블 목록\n    const filteredData = File.browse("pages").filter(item => !excludeLabels.includes(item.label)); // 제외 목록에 포함되지 않은( ! ) 데이터만 리턴\n    const langButton = $W("mlc$lang");\n    langButton.changeState(langButton.get("state") == "Layer1" ? "Layer2" : "Layer1");\n    File.set("filter:pages",langButton.get("state") == "Layer1" ? File.browse("pages") : filteredData);\n    $W("t$totalPage").set("text",File.get("filter:pages").length);\n    File.set("lang",langButton.get("state") == "Layer1" ? "ko" : "en");\n    linkTo(1, {reset: true});\n}\n\nfunction onClickPrev() {\n    const result = File.get("filter:pages").findIndex(p => p.label == `Page ${parseInt(get("$labelPageNum"))}`);\n    linkTo(File.get("filter:pages")[result-1].id, {reset: true});\n}\n\nfunction onClickNext() {\n    const result = File.get("filter:pages").findIndex(p => p.label == `Page ${parseInt(get("$labelPageNum"))}`);\n    linkTo(File.get("filter:pages")[result+1].id, {reset: true});\n}\n\nfunction onClickFloors() {\n    const floorsButton = $W("mlc$menu_floors");\n    floorsButton.changeState(floorsButton.get("state") == "Layer1" ? "Layer2" : "Layer1");\n    $W("mlc$menu_floors_sub").set("visibility",floorsButton.get("state") == "Layer2" ? "visible" : "hidden");\n}\n\n\n\n',
      },
